    if (mmap_handle_ != 0) {
        // Unmap the partition and release associated resources
        esp_partition_munmap(mmap_handle_);

        // Reset internal state to prevent double-free or invalid access
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
    }

    // Reset other state variables
    partition_valid_ = false;
    checksum_valid_ = false;

    // Clear the assets map
    assets_.clear();

    // Note: partition_ is a const pointer to esp_partition_t and should not be freed
    // as it's managed by the ESP-IDF partition system
}

