bool Assets::InitializePartition()
{
    // Find the assets partition
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition_ == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        partition_valid_ = false;
        return false;
    }

    // Check minimum size requirement
    if (partition_->size < sizeof(mmap_assets_table)) {
        ESP_LOGE(TAG, "Assets partition too small: %lu bytes", partition_->size);
        partition_valid_ = false;
        return false;
    }

    // Map the partition into memory
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, SPI_FLASH_MMAP_DATA, 
                                       (const void**)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        partition_valid_ = false;
        return false;
    }

    // Perform checksum validation
    // Assuming checksum is stored at the beginning and covers the rest of the data
    // Let's assume first 4 bytes are checksum, followed by actual data
    if (partition_->size < 4) {
        ESP_LOGE(TAG, "Assets partition too small for checksum");
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        partition_valid_ = false;
        return false;
    }

    uint32_t stored_checksum = *((uint32_t*)mmap_root_);
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_ + 4, partition_->size - 4);

    if (stored_checksum != calculated_checksum) {
        ESP_LOGE(TAG, "Checksum mismatch: stored=0x%04X, calculated=0x%04X", 
                 stored_checksum, calculated_checksum);
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        checksum_valid_ = false;
        partition_valid_ = false;
        return false;
    }

    checksum_valid_ = true;

    // Build in-memory index of assets
    assets_.clear();

    // Parse the asset table starting after the checksum (4 bytes)
    size_t offset = 4;
    const char* data_ptr = mmap_root_ + offset;

    // Iterate through asset entries until we reach the end or find an empty entry
    while (offset < partition_->size && 
           offset + sizeof(mmap_assets_table) <= partition_->size) {

        const mmap_assets_table* entry = (const mmap_assets_table*)(mmap_root_ + offset);

        // Check if this is a valid entry (non-empty name)
        if (entry->asset_name[0] == '\0') {
            break; // End of asset table
        }

        // Validate that the asset fits within the partition
        size_t asset_end_offset = entry->asset_offset + entry->asset_size + 2; // +2 for ZZ header
        if (asset_end_offset > partition_->size) {
            ESP_LOGW(TAG, "Asset %s extends beyond partition boundary", entry->asset_name);
            break;
        }

        // Add asset to our index
        Asset asset;
        asset.size = entry->asset_size;
        asset.offset = entry->asset_offset;

        std::string asset_name(entry->asset_name);
        assets_[asset_name] = asset;

        ESP_LOGD(TAG, "Indexed asset: %s, size=%u, offset=%u", 
                 entry->asset_name, entry->asset_size, entry->asset_offset);

        // Move to next entry
        offset += sizeof(mmap_assets_table);
    }

    partition_valid_ = true;
    ESP_LOGI(TAG, "Assets partition initialized successfully with %d assets", assets_.size());

    return true;
}

