bool Assets::Apply()
{
    if (!partition_valid_ || !checksum_valid_) {
        ESP_LOGE(TAG, "Assets partition is not valid or checksum failed");
        return false;
    }

    // Load index.json configuration
    void* index_data = nullptr;
    size_t index_size = 0;
    if (!GetAssetData("index.json", index_data, index_size)) {
        ESP_LOGE(TAG, "Failed to load index.json");
        return false;
    }

    // Parse JSON configuration
    cJSON* json = cJSON_ParseWithLength((const char*)index_data, index_size);
    if (json == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return false;
    }

    bool result = true;

    // Validate asset version
    cJSON* version_obj = cJSON_GetObjectItem(json, "version");
    if (version_obj && cJSON_IsString(version_obj)) {
        ESP_LOGI(TAG, "Applying assets version: %s", version_obj->valuestring);
    } else {
        ESP_LOGW(TAG, "No version found in index.json");
    }

    // Apply speech recognition models
    cJSON* speech_models = cJSON_GetObjectItem(json, "speech_models");
    if (speech_models && cJSON_IsArray(speech_models)) {
        int model_count = cJSON_GetArraySize(speech_models);
        ESP_LOGI(TAG, "Loading %d speech recognition models", model_count);

        // Create model list
        if (models_list_) {
            free(models_list_);
        }
        models_list_ = (srmodel_list_t*)calloc(1, sizeof(srmodel_list_t) + model_count * sizeof(model_path_t));
        if (!models_list_) {
            ESP_LOGE(TAG, "Failed to allocate memory for model list");
            cJSON_Delete(json);
            return false;
        }

        models_list_->num = model_count;

        for (int i = 0; i < model_count; i++) {
            cJSON* model_item = cJSON_GetArrayItem(speech_models, i);
            if (model_item && cJSON_IsObject(model_item)) {
                cJSON* model_name = cJSON_GetObjectItem(model_item, "name");
                cJSON* model_file = cJSON_GetObjectItem(model_item, "file");

                if (model_name && cJSON_IsString(model_name) && model_file && cJSON_IsString(model_file)) {
                    strncpy(models_list_->models[i].model_name, model_name->valuestring, sizeof(models_list_->models[i].model_name) - 1);
                    strncpy(models_list_->models[i].lang_isocode, model_file->valuestring, sizeof(models_list_->models[i].lang_isocode) - 1);
                    ESP_LOGI(TAG, "Loaded speech model: %s -> %s", model_name->valuestring, model_file->valuestring);
                }
            }
        }
    }

    // Apply UI themes
    cJSON* ui_theme = cJSON_GetObjectItem(json, "ui_theme");
    if (ui_theme && cJSON_IsString(ui_theme)) {
        ESP_LOGI(TAG, "Applying UI theme: %s", ui_theme->valuestring);
        // Apply the theme to LVGL
        lvgl_theme_apply(ui_theme->valuestring);
    }

    // Apply fonts
    cJSON* fonts = cJSON_GetObjectItem(json, "fonts");
    if (fonts && cJSON_IsArray(fonts)) {
        int font_count = cJSON_GetArraySize(fonts);
        ESP_LOGI(TAG, "Loading %d fonts", font_count);

        for (int i = 0; i < font_count; i++) {
            cJSON* font_item = cJSON_GetArrayItem(fonts, i);
            if (font_item && cJSON_IsObject(font_item)) {
                cJSON* font_name = cJSON_GetObjectItem(font_item, "name");
                cJSON* font_file = cJSON_GetObjectItem(font_item, "file");

                if (font_name && cJSON_IsString(font_name) && font_file && cJSON_IsString(font_file)) {
                    void* font_data = nullptr;
                    size_t font_size = 0;

                    if (GetAssetData(font_file->valuestring, font_data, font_size)) {
                        // Register font with LVGL
                        cbin_font_add((const uint8_t*)font_data, font_size);
                        ESP_LOGI(TAG, "Loaded font: %s from %s", font_name->valuestring, font_file->valuestring);
                    } else {
                        ESP_LOGW(TAG, "Failed to load font file: %s", font_file->valuestring);
                    }
                }
            }
        }
    }

    // Apply emojis
    cJSON* emojis = cJSON_GetObjectItem(json, "emojis");
    if (emojis && cJSON_IsObject(emojis)) {
        cJSON* emoji_file = cJSON_GetObjectItem(emojis, "file");
        if (emoji_file && cJSON_IsString(emoji_file)) {
            void* emoji_data = nullptr;
            size_t emoji_size = 0;

            if (GetAssetData(emoji_file->valuestring, emoji_data, emoji_size)) {
                // Apply emoji data to display system
                emote_display_load((const uint8_t*)emoji_data, emoji_size);
                ESP_LOGI(TAG, "Loaded emojis from %s", emoji_file->valuestring);
            } else {
                ESP_LOGW(TAG, "Failed to load emoji file: %s", emoji_file->valuestring);
            }
        }
    }

    // Notify subsystems of asset changes
    auto& app = Application::GetInstance();
    app.OnAssetsApplied();

    cJSON_Delete(json);
    ESP_LOGI(TAG, "Assets applied successfully");
    return result;
}

