bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    ESP_LOGI(TAG, "Starting download from %s", url.c_str());

    // Initialize HTTP client
    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.method = HTTP_METHOD_GET;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == NULL) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Open HTTP connection
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Failed to get content length");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    ESP_LOGI(TAG, "Content length: %d bytes", content_length);

    // Validate content size against partition size
    if ((size_t)content_length > partition_->size) {
        ESP_LOGE(TAG, "Content size (%d) exceeds partition size (%d)", content_length, partition_->size);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase flash memory
    ESP_LOGI(TAG, "Erasing flash partition...");
    err = esp_partition_erase_range(partition_, 0, partition_->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Download and write data in chunks
    const size_t BUFFER_SIZE = 4096;
    uint8_t* buffer = (uint8_t*)malloc(BUFFER_SIZE);
    if (buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    size_t total_written = 0;
    size_t bytes_written = 0;
    int last_progress = -1;
    int64_t start_time = esp_timer_get_time();
    int64_t last_time = start_time;

    // Write header (files count, checksum, length) - placeholder values for now
    uint32_t header_data[3] = {0, 0, (uint32_t)content_length};
    err = esp_partition_write(partition_, 0, header_data, sizeof(header_data));
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write header: %s", esp_err_to_name(err));
        free(buffer);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }
    bytes_written += sizeof(header_data);

    // Download and write asset data
    while (total_written < (size_t)content_length) {
        int bytes_to_read = MIN(BUFFER_SIZE, content_length - total_written);
        int bytes_read = esp_http_client_read(client, (char*)buffer, bytes_to_read);

        if (bytes_read < 0) {
            ESP_LOGE(TAG, "Failed to read HTTP data");
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        if (bytes_read == 0) {
            break; // No more data
        }

        // Write to flash
        err = esp_partition_write(partition_, bytes_written, buffer, bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to flash: %s", esp_err_to_name(err));
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        total_written += bytes_read;
        bytes_written += bytes_read;

        // Calculate and report progress
        int current_progress = (int)((total_written * 100) / content_length);
        int64_t current_time = esp_timer_get_time();

        // Update progress every 1% or at least every 500ms
        if (current_progress != last_progress || (current_time - last_time) > 500000) {
            size_t speed = 0;
            if ((current_time - start_time) > 0) {
                speed = (total_written * 1000000) / (current_time - start_time);
            }

            if (progress_callback) {
                progress_callback(current_progress, speed);
            }

            ESP_LOGI(TAG, "Download progress: %d%%, Speed: %d bytes/sec", current_progress, (int)speed);
            last_progress = current_progress;
            last_time = current_time;
        }
    }

    free(buffer);
    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    // Verify downloaded data
    if (total_written != (size_t)content_length) {
        ESP_LOGE(TAG, "Incomplete download: expected %d, got %d bytes", content_length, total_written);
        return false;
    }

    // Calculate and store checksum
    void* verify_buffer = malloc(content_length);
    if (verify_buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate verification buffer");
        return false;
    }

    err = esp_partition_read(partition_, sizeof(header_data), verify_buffer, content_length);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read back data for verification: %s", esp_err_to_name(err));
        free(verify_buffer);
        return false;
    }

    uint32_t checksum = CalculateChecksum((const char*)verify_buffer, content_length);
    free(verify_buffer);

    // Update header with actual checksum
    header_data[1] = checksum;
    err = esp_partition_write(partition_, 4, &header_data[1], sizeof(uint32_t));
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to update checksum: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "Download completed successfully. Checksum: 0x%lx", checksum);

    // Reinitialize partition to use the new assets
    if (mmap_handle_ != 0) {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
    }

    partition_valid_ = false;
    checksum_valid_ = false;
    assets_.clear();

    return InitializePartition();
}

