std::unique_ptr<Http> Ota::SetupHttp()
{
    auto& board = Board::GetInstance();
    auto network = board.GetNetwork();

    // Create HTTP client instance
    auto http = network->CreateHttp(0);
    if (!http) {
        ESP_LOGE(TAG, "Failed to create HTTP client");
        return nullptr;
    }

    // Set default timeout
    http->SetTimeout(30000); // 30 seconds timeout

    // Set Content-Type header
    http->AddHeader("Content-Type", "application/json");

    // Set User-Agent header
    http->AddHeader("User-Agent", "Device/" CONFIG_DEVICE_MODEL " OTA-Client/1.0");

    // Set Accept-Language header
    http->AddHeader("Accept-Language", LangConfig::GetCurrentLanguage());

    // Add device identification header
    std::string deviceId = board.GetDeviceId();
    if (!deviceId.empty()) {
        http->AddHeader("X-Device-ID", deviceId);
    }

    // Conditionally add serial number header based on device provisioning status
    if (has_serial_number_) {
        http->AddHeader("X-Serial-Number", serial_number_);
    }

    // Set connection keep-alive
    http->AddHeader("Connection", "keep-alive");

    return http;
}

