void Ota::MarkCurrentVersionValid()
{
    // Get the currently running partition
    const esp_partition_t* running_partition = esp_ota_get_running_partition();
    if (running_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Skip validation for factory partition
    if (running_partition->type == ESP_PARTITION_TYPE_APP && 
        running_partition->subtype == ESP_PARTITION_SUBTYPE_APP_FACTORY) {
        ESP_LOGI(TAG, "Running on factory partition, skipping validation");
        return;
    }

    // Check the state of the running partition
    esp_ota_img_states_t partition_state;
    esp_err_t err = esp_ota_get_state_partition(running_partition, &partition_state);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get partition state: %s", esp_err_to_name(err));
        return;
    }

    // Only mark as valid if it's in pending verification state
    if (partition_state == ESP_OTA_IMG_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Current partition is in pending verification state, marking as valid");

        // Mark the current firmware as valid to prevent rollback on next boot
        err = esp_ota_mark_app_valid_cancel_rollback();
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mark app as valid: %s", esp_err_to_name(err));
            return;
        }

        ESP_LOGI(TAG, "Successfully marked current firmware version as valid");
    } else {
        ESP_LOGI(TAG, "Current partition is already validated (state: %d)", partition_state);
    }
}

