bool Ota::Upgrade(const std::string &firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    if (firmware_url.empty())
    {
        ESP_LOGE(TAG, "Invalid firmware URL");
        return false;
    }

    auto http = SetupHttp();
    if (!http)
    {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return false;
    }

    if (!http->Open("GET", firmware_url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", firmware_url.c_str());
        return false;
    }

    int status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "HTTP error: %d", status_code);
        http->Close();
        return false;
    }

    const esp_partition_t* update_partition = esp_ota_get_next_update_partition(NULL);
    if (update_partition == nullptr)
    {
        ESP_LOGE(TAG, "Failed to get next update partition");
        http->Close();
        return false;
    }

    esp_ota_handle_t ota_handle;
    esp_err_t err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        http->Close();
        return false;
    }

    constexpr size_t BUFFER_SIZE = 4096;
    std::vector<uint8_t> buffer(BUFFER_SIZE);

    size_t total_bytes_written = 0;
    size_t content_length = http->GetContentLength();

    TickType_t last_tick = xTaskGetTickCount();
    size_t last_bytes = 0;

    while (true)
    {
        ssize_t read_len = http->Read(buffer.data(), buffer.size());
        if (read_len < 0)
        {
            ESP_LOGE(TAG, "Error reading HTTP stream");
            esp_ota_abort(ota_handle);
            http->Close();
            return false;
        }

        if (read_len == 0)
        {
            break; // EOF
        }

        err = esp_ota_write(ota_handle, buffer.data(), read_len);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            esp_ota_abort(ota_handle);
            http->Close();
            return false;
        }

        total_bytes_written += read_len;

        TickType_t current_tick = xTaskGetTickCount();
        uint32_t elapsed_ms = (current_tick - last_tick) * portTICK_PERIOD_MS;

        if (elapsed_ms >= 1000 || total_bytes_written == content_length)
        {
            size_t delta_bytes = total_bytes_written - last_bytes;
            size_t speed_bps = (delta_bytes * 1000) / (elapsed_ms + 1); // avoid div by zero

            int progress = (content_length > 0) ? static_cast<int>((total_bytes_written * 100) / content_length) : 0;
            if (progress > 100) progress = 100;

            if (callback)
            {
                callback(progress, speed_bps);
            }

            last_bytes = total_bytes_written;
            last_tick = current_tick;
        }
    }

    err = esp_ota_end(ota_handle);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)", esp_err_to_name(err));
        http->Close();
        return false;
    }

    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)", esp_err_to_name(err));
        http->Close();
        return false;
    }

    http->Close();
    ESP_LOGI(TAG, "OTA upgrade completed successfully.");
    return true;
}

