bool Ota::IsNewVersionAvailable(const std::string &currentVersion, const std::string &newVersion)
{
    std::vector<int> current = ParseVersion(currentVersion);
    std::vector<int> candidate = ParseVersion(newVersion);

    size_t max_segments = std::max(current.size(), candidate.size());

    for (size_t i = 0; i < max_segments; ++i) {
        int curr_seg = (i < current.size()) ? current[i] : 0;
        int cand_seg = (i < candidate.size()) ? candidate[i] : 0;

        if (cand_seg > curr_seg) {
            return true;
        } else if (cand_seg < curr_seg) {
            return false;
        }
    }

    // All segments were equal
    return false;
}

