    // Only attempt to commit if in read-write mode and there are unsaved changes
    if (read_write_ && dirty_ && nvs_handle_ != 0) {
        esp_err_t err = nvs_commit(nvs_handle_);
        if (err != ESP_OK) {
            ESP_LOGW(TAG, "Failed to commit NVS settings: %s", esp_err_to_name(err));
        }
    }

    // Always close the NVS handle to prevent resource leaks
    if (nvs_handle_ != 0) {
        nvs_close(nvs_handle_);
    }
}

