void Settings::EraseAll() {
    if (!read_write_) {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
        return;
    }

    esp_err_t err = nvs_erase_all(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase all keys in namespace %s: %s", ns_.c_str(), esp_err_to_name(err));
        return;
    }

    err = nvs_commit(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to commit changes after erase in namespace %s: %s", ns_.c_str(), esp_err_to_name(err));
    }
}

