bool AudioCodec::InputData(std::vector<int16_t>& data) {
    // Check if input is enabled
    if (!input_enabled_) {
        return false;
    }

    // Resize buffer to accommodate one frame worth of samples
    data.resize(AUDIO_CODEC_DMA_FRAME_NUM);

    // Attempt to read audio samples using the pure virtual Read function
    int samples_read = Read(data.data(), AUDIO_CODEC_DMA_FRAME_NUM);

    // Handle errors or end-of-stream
    if (samples_read <= 0) {
        data.clear();
        return false;
    }

    // Resize to actual amount of data read
    data.resize(samples_read);
    return true;
}

