void Es8388AudioCodec::SetOutputVolume(int volume) {
    // Validate and clamp the input volume level to the supported range
    if (volume < 0) {
        volume = 0;
    } else if (volume > 100) {
        volume = 100;
    }

    {
        // Lock to ensure thread safety when accessing hardware interface
        std::lock_guard<std::mutex> lock(data_if_mutex_);

        // Update the internal software volume state
        output_volume_ = volume;

        // Write the adjusted volume value to the codec hardware if output is enabled
        if (output_enabled_ && output_dev_) {
            ESP_ERROR_CHECK(esp_codec_dev_set_out_vol(output_dev_, volume));
        }
    }

    // Log the volume change
    ESP_LOGI(TAG, "Output volume set to %d%%", volume);
}

