bool AfeWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    // Step 1: Configure Audio Codec for Duplex I2S @ 24kHz
    if (!codec->Configure(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX, 24000)) {
        ESP_LOGE(TAG, "Failed to configure audio codec");
        return false;
    }

    // Step 2: Load wake word models
    models_ = esp_srmodel_init(models_list);
    if (models_ == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize speech recognition models");
        return false;
    }

    // Retrieve wake word names for logging/debugging purposes
    int num_wake_words = esp_srmodel_get_wakenet_model_num(models_);
    wake_words_.resize(num_wake_words);
    for (int i = 0; i < num_wake_words; ++i) {
        wake_words_[i] = esp_srmodel_get_wakenet_model_name_by_index(models_, i);
        ESP_LOGI(TAG, "Loaded wake word model: %s", wake_words_[i].c_str());
    }

    // Step 3: Initialize AFE processing pipeline with default config
    afe_config_t config = {
        .aec_en = true,
        .se_en = false,
        .vad_en = true,
        .wakenet_en = true,
        .voice_communication_agc_en = false,
        .state_monitor_en = false,
        .memory_alloc_mode = AFE_MEMORY_ALLOC_MORE_PSRAM,
        .rb_size = 128 * 1024, // 128KB ring buffer
        .affinity_mask = 0
    };

    afe_data_ = afe_iface_->create_from_config(&config);
    if (afe_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create AFE instance");
        return false;
    }

    // Step 4: Start audio detection task
    static StackType_t detection_task_stack[4096];
    static StaticTask_t detection_task_buffer;

    detection_task_handle_ = xTaskCreateStatic(
        [](void *arg) {
            reinterpret_cast<AfeWakeWord*>(arg)->AudioDetectionTask();
        },
        "AfeWakeWordDetection",
        4096,
        this,
        5,
        detection_task_stack,
        &detection_task_buffer
    );

    if (detection_task_handle_ == NULL) {
        ESP_LOGE(TAG, "Failed to create audio detection task");
        return false;
    }

    ESP_LOGI(TAG, "AFE Wake Word initialized successfully");

    return true;
}

