void AfeWakeWord::AudioDetectionTask()
{
    while (true) {
        // Wait for detection to be enabled
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                             DETECTION_RUNNING_EVENT, 
                                             pdFALSE, 
                                             pdTRUE, 
                                             portMAX_DELAY);

        if (bits & DETECTION_RUNNING_EVENT) {
            // Check if AFE is properly initialized
            if (afe_data_ == nullptr || afe_iface_ == nullptr) {
                vTaskDelay(pdMS_TO_TICKS(10));
                continue;
            }

            // Fetch processed audio data from AFE
            int fetch_result = afe_iface_->fetch_result(afe_data_);

            // Check if wake word was detected
            if (fetch_result >= 0 && fetch_result < static_cast<int>(wake_words_.size())) {
                ESP_LOGI(TAG, "Wake word detected: %s", wake_words_[fetch_result].c_str());

                // Stop detection temporarily
                xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);

                // Store the last detected wake word
                last_detected_wake_word_ = wake_words_[fetch_result];

                // Get and store the wake word audio data
                const int16_t* wake_word_data = nullptr;
                size_t wake_word_samples = 0;
                afe_iface_->get_wakenet_result(afe_data_, &wake_word_data, &wake_word_samples);

                if (wake_word_data != nullptr && wake_word_samples > 0) {
                    StoreWakeWordData(wake_word_data, wake_word_samples);
                    EncodeWakeWordData();
                }

                // Trigger the callback if registered
                if (wake_word_detected_callback_) {
                    wake_word_detected_callback_(last_detected_wake_word_);
                }

                // Reset AFE buffer for next detection
                if (afe_data_ != nullptr) {
                    afe_iface_->reset_buffer(afe_data_);
                }

                // Resume detection
                xEventGroupSetBits(event_group_, DETECTION_RUNNING_EVENT);
            }
        }

        // Small delay to prevent busy waiting
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

