    // Allocate task stack and buffer using SPIRAM with fallback to internal memory
    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(
            4096 * sizeof(StackType_t), 
            MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT
        );
        if (wake_word_encode_task_stack_ == nullptr) {
            wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(
                4096 * sizeof(StackType_t), 
                MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT
            );
        }
    }

    if (wake_word_encode_task_buffer_ == nullptr) {
        wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_malloc(
            sizeof(StaticTask_t), 
            MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT
        );
        if (wake_word_encode_task_buffer_ == nullptr) {
            wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_malloc(
                sizeof(StaticTask_t), 
                MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT
            );
        }
    }

    // Create the encoding task
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            AfeWakeWord* this_ = (AfeWakeWord*)arg;

            // Initialize Opus encoder with low complexity settings
            OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
            opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));  // Low complexity for real-time
            opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000));
            opus_encoder_ctl(encoder, OPUS_SET_VBR(1));

            const int frame_size = 512; // Assuming 30ms at 16kHz
            const int max_packet_size = 4000;
            std::vector<uint8_t> encoded_packet(max_packet_size);

            while (true) {
                // Wait for PCM data to be available
                std::unique_lock<std::mutex> lock(this_->wake_word_mutex_);
                if (this_->wake_word_pcm_.empty()) {
                    lock.unlock();
                    vTaskDelay(pdMS_TO_TICKS(10));
                    continue;
                }

                // Get PCM data
                std::vector<int16_t> pcm_data = std::move(this_->wake_word_pcm_.front());
                this_->wake_word_pcm_.pop_front();
                lock.unlock();

                // Process PCM data through Opus encoder
                int encoded_bytes = opus_encode(
                    encoder,
                    pcm_data.data(),
                    frame_size,
                    encoded_packet.data(),
                    max_packet_size
                );

                if (encoded_bytes > 0) {
                    // Store encoded Opus packet in thread-safe buffer
                    std::lock_guard<std::mutex> guard(this_->wake_word_mutex_);
                    this_->wake_word_opus_.emplace_back(
                        std::vector<uint8_t>(encoded_packet.begin(), 
                                           encoded_packet.begin() + encoded_bytes)
                    );

                    // Signal completion via condition variable
                    this_->wake_word_cv_.notify_one();
                }
            }

            opus_encoder_destroy(encoder);
        },
        "wake_word_encode",
        4096,
        this,
        5,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );
