bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t> &opus)
{
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there's data available in the queue
    wake_word_cv_.wait(lock, [this] { return !wake_word_opus_.empty(); });

    // Retrieve the first element from the queue
    opus = std::move(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    // Return true if the data is valid (non-empty), false otherwise
    // The encoding task pushes an empty vector as a sentinel to indicate completion
    return !opus.empty();
}

