void CustomWakeWord::ParseWakenetModelConfig()
{
    // Get the index.json file path from the model list
    const char* index_json_path = esp_srmodel_filter(models_, "index", "json");
    if (index_json_path == nullptr) {
        ESP_LOGE(TAG, "index.json not found in model directory");
        return;
    }

    // Read the JSON file content
    char* json_content = esp_srmodel_load(index_json_path);
    if (json_content == nullptr) {
        ESP_LOGE(TAG, "Failed to load index.json from %s", index_json_path);
        return;
    }

    // Parse JSON content
    cJSON* root = cJSON_Parse(json_content);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        free(json_content);
        return;
    }

    // Extract language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item != nullptr && cJSON_IsString(language_item)) {
        language_ = std::string(language_item->valuestring);
        ESP_LOGI(TAG, "Parsed language: %s", language_.c_str());
    } else {
        language_ = "en"; // default fallback
        ESP_LOGW(TAG, "Language not found in config, using default: %s", language_.c_str());
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item != nullptr && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Parsed duration: %d", duration_);
    } else {
        duration_ = 5000; // default fallback in milliseconds
        ESP_LOGW(TAG, "Duration not found in config, using default: %d", duration_);
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item != nullptr && cJSON_IsNumber(threshold_item)) {
        threshold_ = (float)threshold_item->valuedouble;
        ESP_LOGI(TAG, "Parsed threshold: %f", threshold_);
    } else {
        threshold_ = 0.6f; // default fallback
        ESP_LOGW(TAG, "Threshold not found in config, using default: %f", threshold_);
    }

    // Extract commands
    cJSON* commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array != nullptr && cJSON_IsArray(commands_array)) {
        commands_.clear();
        int commands_count = cJSON_GetArraySize(commands_array);
        ESP_LOGI(TAG, "Found %d commands in config", commands_count);

        for (int i = 0; i < commands_count; i++) {
            cJSON* command_obj = cJSON_GetArrayItem(commands_array, i);
            if (command_obj != nullptr && cJSON_IsObject(command_obj)) {
                Command cmd;

                // Extract command name
                cJSON* command_item = cJSON_GetObjectItem(command_obj, "command");
                if (command_item != nullptr && cJSON_IsString(command_item)) {
                    cmd.command = std::string(command_item->valuestring);
                }

                // Extract display text
                cJSON* text_item = cJSON_GetObjectItem(command_obj, "text");
                if (text_item != nullptr && cJSON_IsString(text_item)) {
                    cmd.text = std::string(text_item->valuestring);
                } else {
                    cmd.text = cmd.command; // fallback to command name
                }

                // Extract action
                cJSON* action_item = cJSON_GetObjectItem(command_obj, "action");
                if (action_item != nullptr && cJSON_IsString(action_item)) {
                    cmd.action = std::string(action_item->valuestring);
                } else {
                    cmd.action = "command"; // default action
                }

                commands_.push_back(cmd);
                ESP_LOGI(TAG, "Parsed command[%d]: command='%s', text='%s', action='%s'", 
                         i, cmd.command.c_str(), cmd.text.c_str(), cmd.action.c_str());
            }
        }
    } else {
        ESP_LOGW(TAG, "No valid commands array found in config");
    }

    // Clean up
    cJSON_Delete(root);
    free(json_content);
}

