bool CustomWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    if (!codec || !models_list) {
        ESP_LOGE(TAG, "Invalid arguments: codec or models_list is null");
        return false;
    }

    // Step 1: Save audio codec reference
    codec_ = codec;

    // Step 2: Parse wakeword model configuration from assets/index.json
    ParseWakenetModelConfig();

    if (language_.empty()) {
        ESP_LOGE(TAG, "Language not found in index.json");
        return false;
    }

    // Step 3: Find matching multinet model based on language
    const esp_mn_iface_t *iface = nullptr;
    const char *model_name = nullptr;

    for (int i = 0; i < models_list->num; i++) {
        const srmodel_t *model = &models_list->list[i];
        if (strcmp(model->lang, language_.c_str()) == 0 &&
            strncmp(model->name, "multinet", strlen("multinet")) == 0) {
            iface = esp_mn_create(model->name);
            model_name = model->name;
            break;
        }
    }

    if (!iface || !model_name) {
        ESP_LOGE(TAG, "No suitable multinet model found for language '%s'", language_.c_str());
        return false;
    }

    multinet_ = iface;
    ESP_LOGI(TAG, "Loaded multinet model: %s", model_name);

    // Step 4: Create model data
    multinet_model_data_ = multinet_->create(model_name, DEFAULT_AUDIO_SAMPLE_RATE);
    if (!multinet_model_data_) {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Step 5: Configure model parameters
    if (duration_ > 0) {
        multinet_->set_duration(multinet_model_data_, duration_);
    }

    if (threshold_ >= 0.0) {
        multinet_->set_threshold(multinet_model_data_, threshold_);
    }

    // Step 6: Register custom commands
    for (const auto &cmd : commands_) {
        int ret = multinet_->add_command(multinet_model_data_, cmd.command.c_str(), cmd.text.c_str());
        if (ret != 0) {
            ESP_LOGW(TAG, "Failed to add command ID %d: %s", ret, cmd.text.c_str());
        } else {
            ESP_LOGI(TAG, "Registered command: %s -> %s", cmd.command.c_str(), cmd.text.c_str());
        }
    }

    // Step 7: Finalize setup
    models_ = models_list;

    ESP_LOGI(TAG, "Custom wake word initialized successfully.");
    return true;
}

