void CustomWakeWord::Feed(const std::vector<int16_t> &data)
{
    if (!running_ || data.empty() || multinet_model_data_ == nullptr) {
        return;
    }

    // Extract left channel if stereo (assuming interleaved stereo data)
    std::vector<int16_t> mono_data;
    const std::vector<int16_t>* process_data = &data;

    // Check if stereo (even number of samples and likely stereo based on typical audio configs)
    // Most common case: stereo data has even number of samples with L/R interleaved
    if (data.size() % 2 == 0) {
        mono_data.reserve(data.size() / 2);
        for (size_t i = 0; i < data.size(); i += 2) {
            mono_data.push_back(data[i]); // Take left channel (first of each pair)
        }
        process_data = &mono_data;
    }

    // Get the required chunk size for the multinet model
    size_t chunk_size = multinet_->get_samp_chunksize(multinet_model_data_);

    // Process data in chunks
    for (size_t i = 0; i + chunk_size <= process_data->size(); i += chunk_size) {
        // Create a chunk of audio data
        std::vector<int16_t> chunk(process_data->begin() + i, process_data->begin() + i + chunk_size);

        // Store the audio data for potential encoding later
        StoreWakeWordData(chunk);

        // Run multinet detection on this chunk
        esp_mn_state_t* result = multinet_->detect(multinet_model_data_, chunk.data());

        // Check if wake word was detected
        if (result && result->state == ESP_MN_STATE_DETECT && result->command_id > 0) {
            // Validate command ID range
            if (result->command_id > 0 && result->command_id <= static_cast<int>(commands_.size())) {
                // Get the detected wake word
                const std::string& detected_wake_word = commands_[result->command_id - 1].display_text;

                // Stop processing
                running_ = false;

                // Trigger callback if set
                if (wake_word_detected_callback_) {
                    wake_word_detected_callback_(detected_wake_word);
                }

                // Encode the stored wake word data for potential upload/transmission
                EncodeWakeWordData();

                return; // Exit after detection
            }
        }
    }
}

