            heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT)
        );
        if (wake_word_encode_task_buffer_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate task buffer for wake word encode task");
            return;
        }
    }

    // Create the background task for encoding
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            CustomWakeWord* wake_word = static_cast<CustomWakeWord*>(arg);

            // Initialize Opus encoder with low complexity settings
            int error;
            OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, &error);
            if (error != OPUS_OK || encoder == nullptr) {
                ESP_LOGE(TAG, "Failed to create Opus encoder: %s", opus_strerror(error));
                vTaskDelete(nullptr);
                return;
            }

            // Set low complexity encoding
            opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
            opus_encoder_ctl(encoder, OPUS_SET_BITRATE(OPUS_AUTO));

            // Process each PCM segment
            std::vector<uint8_t> encoded_data;
            const size_t max_packet_size = 4000;
            std::vector<unsigned char> encoded_packet(max_packet_size);

            {
                std::lock_guard<std::mutex> lock(wake_word->wake_word_mutex_);

                for (const auto& pcm_segment : wake_word->wake_word_pcm_) {
                    if (pcm_segment.empty()) continue;

                    int encoded_bytes = opus_encode(
                        encoder,
                        pcm_segment.data(),
                        pcm_segment.size(),
                        encoded_packet.data(),
                        max_packet_size
                    );

                    if (encoded_bytes > 0) {
                        // Add encoded packet to result
                        encoded_data.insert(encoded_data.end(), encoded_packet.begin(), encoded_packet.begin() + encoded_bytes);
                    } else {
                        ESP_LOGW(TAG, "Opus encoding failed with error: %s", opus_strerror(encoded_bytes));
                    }
                }

                // Append termination marker (empty Opus packet)
                int termination_bytes = opus_encode(encoder, nullptr, 0, encoded_packet.data(), max_packet_size);
                if (termination_bytes > 0) {
                    encoded_data.insert(encoded_data.end(), encoded_packet.begin(), encoded_packet.begin() + termination_bytes);
                }

                // Store encoded data
                wake_word->wake_word_opus_.push_back(std::move(encoded_data));
            }

            // Signal that encoded data is available
            wake_word->wake_word_cv_.notify_one();

            // Clean up encoder
            opus_encoder_destroy(encoder);

            // Clear PCM data as it's now encoded
            wake_word->wake_word_pcm_.clear();

            vTaskDelete(nullptr);
        },
        "WakeWordEncode",
        CONFIG_CUSTOM_WAKE_WORD_ENCODE_TASK_STACK_SIZE,
        this,
        CONFIG_CUSTOM_WAKE_WORD_ENCODE_TASK_PRIORITY,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (wake_word_encode_task_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
    }
}

