void SetOutputState(uint8_t bit, uint8_t level)
{
    // Determine port register based on bit index
    uint8_t reg_addr;
    if (bit < 8) {
        reg_addr = 0x02; // Port 0
    } else {
        reg_addr = 0x03; // Port 1
        bit -= 8;
    }

    // Read current register value
    uint8_t current_value = ReadReg(reg_addr);

    // Update the specific bit
    if (level) {
        current_value |= (1 << bit);  // Set bit
    } else {
        current_value &= ~(1 << bit); // Clear bit
    }

    // Write updated value back to register
    WriteReg(reg_addr, current_value);
}

