{
public:
    XL9555(i2c_master_bus_handle_t i2c_bus, uint8_t addr) : I2cDevice(i2c_bus, addr)
    {
        WriteReg(0x06, 0x03);
        WriteReg(0x07, 0xF0);
    }

    void SetOutputState(uint8_t bit, uint8_t level)
    {
        uint16_t data;
        int index = bit;

        if (bit < 8)
        {
            data = ReadReg(0x02);
        }
        else
        {
            data = ReadReg(0x03);
            index -= 8;
        }

        data = (data & ~(1 << index)) | (level << index);

        if (bit < 8)
        {
            WriteReg(0x02, data);
        }
        else
        {
            WriteReg(0x03, data);
        }
    }
};

