void FrequencyDetector::ProcessSample(float sample)
{
    // Get previous state values
    float s_minus_1 = state_buffer_[1];  // S[-1]
    float s_minus_2 = state_buffer_[0];  // S[-2]

    // Apply second-order IIR filter (Goertzel algorithm difference equation)
    // S[n] = x[n] + 2*cos(w) * S[n-1] - S[n-2]
    float s_current = sample + filter_coefficient_ * s_minus_1 - s_minus_2;

    // Update state buffer with new values
    state_buffer_[0] = s_minus_1;  // Shift S[-1] to S[-2]
    state_buffer_[1] = s_current;  // Store new value as S[-1]
}

