float FrequencyDetector::GetAmplitude() const
{
    // Check if sufficient signal history is available (at least two samples)
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Retrieve previous two signal samples from the state buffer
    // The buffer contains [S[-1], S[0]] where S[-1] is second to last and S[0] is last
    auto it = state_buffer_.rbegin();
    float s_current = *it;         // S[0] - current sample
    float s_minus_1 = *(++it);     // S[-1] - previous sample

    // Compute real and imaginary components using cosine and sine coefficients
    // Real part: S[0] - S[-2]
    // For Goertzel algorithm: S[-2] = S[0] - 2*cos* S[-1] + S[-2]
    // But we need to reconstruct S[-2] from our current state
    // Looking at ProcessSample, we store S[-1] and S[current] 
    // So we actually have S[-1] and S[0] in our buffer
    // To get the proper Goertzel output, we compute:
    float real_part = s_current - cos_coefficient_ * s_minus_1;
    float imag_part = sin_coefficient_ * s_minus_1;

    // Calculate amplitude as the normalized square root of summed squares
    float magnitude_squared = real_part * real_part + imag_part * imag_part;
    float amplitude = std::sqrt(magnitude_squared);

    // Normalize by half the window size
    return amplitude / (static_cast<float>(window_size_) * 0.5f);
}

