AudioSignalProcessor::AudioSignalProcessor(size_t sample_rate, size_t mark_frequency, size_t space_frequency,
                                           size_t bit_rate, size_t window_size)
    : sample_rate_(sample_rate)
    , mark_frequency_(mark_frequency)
    , space_frequency_(space_frequency)
    , bit_rate_(bit_rate)
    , window_size_(window_size)
{
    // Validate sample rate divisibility by bit rate and log warning if not
    if (sample_rate_ % bit_rate_ != 0) {
        ESP_LOGW(kLogTag, "Sample rate (%zu) is not divisible by bit rate (%zu)", sample_rate_, bit_rate_);
    }

    // Determine number of samples per bit from sample rate and bit rate
    samples_per_bit_ = sample_rate_ / bit_rate_;

    // Calculate normalized frequencies for mark and space tones
    float normalized_mark_freq = static_cast<float>(mark_frequency_) / static_cast<float>(sample_rate_);
    float normalized_space_freq = static_cast<float>(space_frequency_) / static_cast<float>(sample_rate_);

    // Initialize frequency detectors for mark and space using normalized frequencies
    mark_detector_ = std::make_unique<FrequencyDetector>(normalized_mark_freq, window_size_);
    space_detector_ = std::make_unique<FrequencyDetector>(normalized_space_freq, window_size_);

    // Set input buffer size to window size
    input_buffer_size_ = window_size_;

    // Initialize output sample counter
    output_sample_count_ = 0;
}

