bool AudioDataBuffer::ProcessProbabilityData(const std::vector<float> &probabilities, float threshold)
{
    bool data_complete = false;

    for (float probability : probabilities)
    {
        // Step 1: Convert probability to binary bit using threshold
        uint8_t bit = (probability >= threshold) ? 1 : 0;

        switch (current_state_)
        {
            case DataReceptionState::kInactive:
                // Buffer bits for identifier matching
                identifier_buffer_.push_back(bit);

                // Maintain buffer size to match identifier patterns
                if (identifier_buffer_.size() > identifier_buffer_size_)
                {
                    identifier_buffer_.pop_front();
                }

                // Check if start transmission pattern is matched
                if (identifier_buffer_.size() >= start_of_transmission_.size())
                {
                    bool start_matched = true;
                    auto buffer_it = identifier_buffer_.end();

                    // Compare from the end of buffer with start pattern
                    for (size_t i = 0; i < start_of_transmission_.size(); ++i)
                    {
                        --buffer_it;
                        if (*buffer_it != start_of_transmission_[start_of_transmission_.size() - 1 - i])
                        {
                            start_matched = false;
                            break;
                        }
                    }

                    if (start_matched)
                    {
                        current_state_ = DataReceptionState::kWaiting;
                        identifier_buffer_.clear();
                        bit_buffer_.clear();
                    }
                }
                break;

            case DataReceptionState::kWaiting:
                // In waiting state, continue buffering bits
                bit_buffer_.push_back(bit);

                // Check if we've reached maximum buffer size
                if (bit_buffer_.size() >= max_bit_buffer_size_)
                {
                    // Buffer overflow, reset to inactive state
                    current_state_ = DataReceptionState::kInactive;
                    ClearBuffers();
                }

                // Also check for end transmission pattern during waiting
                identifier_buffer_.push_back(bit);
                if (identifier_buffer_.size() > identifier_buffer_size_)
                {
                    identifier_buffer_.pop_front();
                }

                // Check if end transmission pattern is matched
                if (identifier_buffer_.size() >= end_of_transmission_.size())
                {
                    bool end_matched = true;
                    auto buffer_it = identifier_buffer_.end();

                    // Compare from the end of buffer with end pattern
                    for (size_t i = 0; i < end_of_transmission_.size(); ++i)
                    {
                        --buffer_it;
                        if (*buffer_it != end_of_transmission_[end_of_transmission_.size() - 1 - i])
                        {
                            end_matched = false;
                            break;
                        }
                    }

                    if (end_matched)
                    {
                        // Process received data
                        if (bit_buffer_.size() >= 8) // Need at least one byte
                        {
                            // Convert bits to bytes
                            std::vector<uint8_t> bytes = ConvertBitsToBytes(bit_buffer_);

                            if (!bytes.empty())
                            {
                                // Extract data and optional checksum
                                size_t data_length = bytes.size();
                                if (enable_checksum_validation_ && data_length > 1)
                                {
                                    // Last byte is checksum
                                    uint8_t received_checksum = bytes.back();
                                    bytes.pop_back(); // Remove checksum from data

                                    // Convert bytes to string
                                    std::string received_data(bytes.begin(), bytes.end());

                                    // Calculate expected checksum
                                    uint8_t calculated_checksum = CalculateChecksum(received_data);

                                    // Validate checksum
                                    if (received_checksum == calculated_checksum)
                                    {
                                        decoded_text = std::move(received_data);
                                        data_complete = true;
                                    }
                                }
                                else
                                {
                                    // No checksum validation, use all data
                                    decoded_text = std::string(bytes.begin(), bytes.end());
                                    data_complete = true;
                                }
                            }
                        }

                        current_state_ = DataReceptionState::kInactive;
                        ClearBuffers();
                    }
                }
                break;
        }
    }

    return data_complete;
}

