std::string Board::GetSystemInfoJson() {
    cJSON *root = cJSON_CreateObject();
    if (root == NULL) {
        return "{}";
    }

    // Hardware information
    cJSON *hardware = cJSON_CreateObject();
    if (hardware != NULL) {
        // Chip information
        esp_chip_info_t chip_info;
        esp_chip_info(&chip_info);

        const char* model = "Unknown";
        switch (chip_info.model) {
            case CHIP_ESP32: model = "ESP32"; break;
            case CHIP_ESP32S2: model = "ESP32-S2"; break;
            case CHIP_ESP32S3: model = "ESP32-S3"; break;
            case CHIP_ESP32C3: model = "ESP32-C3"; break;
            case CHIP_ESP32H2: model = "ESP32-H2"; break;
            case CHIP_ESP32C2: model = "ESP32-C2"; break;
            case CHIP_ESP32C6: model = "ESP32-C6"; break;
            case CHIP_ESP32H4: model = "ESP32-H4"; break;
            case CHIP_ESP32P4: model = "ESP32-P4"; break;
            case CHIP_ESP32N3: model = "ESP32-N3"; break;
            default: model = "Unknown"; break;
        }
        cJSON_AddStringToObject(hardware, "chip_model", model);
        cJSON_AddNumberToObject(hardware, "chip_cores", chip_info.cores);

        // Flash size
        uint32_t flash_size = 0;
        esp_flash_get_size(NULL, &flash_size);
        cJSON_AddNumberToObject(hardware, "flash_size", flash_size);

        // MAC address
        uint8_t mac[6];
        esp_read_mac(mac, ESP_MAC_WIFI_STA);
        char mac_str[18];
        snprintf(mac_str, sizeof(mac_str), "%02x:%02x:%02x:%02x:%02x:%02x",
                 mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
        cJSON_AddStringToObject(hardware, "mac_address", mac_str);

        cJSON_AddItemToObject(root, "hardware", hardware);
    }

    // Application metadata
    cJSON *application = cJSON_CreateObject();
    if (application != NULL) {
        const esp_app_desc_t* app_desc = esp_app_get_description();
        if (app_desc != NULL) {
            cJSON_AddStringToObject(application, "name", app_desc->project_name);
            cJSON_AddStringToObject(application, "version", app_desc->version);
        }
        cJSON_AddStringToObject(application, "compile_time", __DATE__ " " __TIME__);
        cJSON_AddItemToObject(root, "application", application);
    }

    // Runtime information
    cJSON *runtime = cJSON_CreateObject();
    if (runtime != NULL) {
        // Memory information
        cJSON_AddNumberToObject(runtime, "min_free_heap", esp_get_minimum_free_heap_size());
        cJSON_AddNumberToObject(runtime, "free_heap", esp_get_free_heap_size());

        // UUID
        cJSON_AddStringToObject(runtime, "uuid", uuid_.c_str());

        cJSON_AddItemToObject(root, "runtime", runtime);
    }

    // Partition information
    cJSON *partition = cJSON_CreateObject();
    if (partition != NULL) {
        const esp_partition_t* running = esp_ota_get_running_partition();
        if (running != NULL) {
            cJSON_AddStringToObject(partition, "running_partition", running->label);
            cJSON_AddNumberToObject(partition, "partition_size", running->size);
        }
        cJSON_AddItemToObject(root, "partition", partition);
    }

    // Convert to JSON string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result;
    if (json_string != NULL) {
        result = std::string(json_string);
        cJSON_free(json_string);
    }

    cJSON_Delete(root);
    return result;
}

