void Button::OnMultipleClick(std::function<void()> callback, uint8_t click_count) {
    if (button_handle_ == nullptr || click_count == 0) {
        return;
    }

    // Store user-provided values
    on_multiple_click_ = callback;
    target_click_count_ = click_count;
    current_click_count_ = 0;

    // Create a one-shot timer to reset the click counter after timeout
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = [](void* arg) {
        Button* btn = static_cast<Button*>(arg);
        btn->current_click_count_ = 0; // Reset click count on timeout
    };
    timer_args.arg = this;
    timer_args.name = "multi_click_reset";

    if (click_reset_timer_ != nullptr) {
        esp_timer_stop(click_reset_timer_);
        esp_timer_delete(click_reset_timer_);
    }
    esp_timer_create(&timer_args, &click_reset_timer_);

    // Register single-click handler to increment count and check for match
    iot_button_register_cb(button_handle_, BUTTON_SINGLE_CLICK, nullptr,
        [](void* handle, void* usr_data) {
            Button* button = static_cast<Button*>(usr_data);

            button->current_click_count_++;

            // Restart the reset timer each time a click happens
            esp_timer_stop(button->click_reset_timer_);
            esp_timer_start_once(button->click_reset_timer_, 300000); // 300 ms timeout

            // If reached desired click count, execute callback
            if (button->current_click_count_ >= button->target_click_count_) {
                button->current_click_count_ = 0;
                if (button->on_multiple_click_) {
                    button->on_multiple_click_();
                }
            }
        }, this);
}

