void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data)
{
    // Notify external callback if registered
    if (network_event_callback_) {
        network_event_callback_(event, data);
    }

    switch (event) {
        case NetworkEvent::Scanning:
            ESP_LOGI(TAG, "WiFi scanning started");
            // Update application state to show scanning
            Application::GetInstance().SetDeviceState(kDeviceStateWifiScanning);
            break;

        case NetworkEvent::Connecting:
            ESP_LOGI(TAG, "Attempting to connect to WiFi network: %s", data.c_str());
            // Update application state to show connecting
            Application::GetInstance().SetDeviceState(kDeviceStateWifiConnecting);
            break;

        case NetworkEvent::Connected:
            ESP_LOGI(TAG, "Successfully connected to WiFi network: %s", data.c_str());
            // Stop the connection timeout timer
            if (connect_timer_) {
                esp_timer_stop(connect_timer_);
            }

            // Exit config mode if we were in it
            if (in_config_mode_) {
                in_config_mode_ = false;
            }

            // Update application state to show connected
            Application::GetInstance().SetDeviceState(kDeviceStateWifiConnected);

            // Show notification of successful connection
            GetDisplay()->ShowNotification((std::string(Lang::Strings::WIFI_CONNECTED) + ": " + data).c_str());
            break;

        case NetworkEvent::Disconnected:
            ESP_LOGI(TAG, "WiFi disconnected");
            // Update application state to show disconnected
            Application::GetInstance().SetDeviceState(kDeviceStateWifiDisconnected);
            break;

        case NetworkEvent::WifiConfigModeEnter:
            ESP_LOGI(TAG, "Entering WiFi configuration mode");
            in_config_mode_ = true;
            // Update application state to show configuring
            Application::GetInstance().SetDeviceState(kDeviceStateWifiConfiguring);
            break;

        case NetworkEvent::WifiConfigModeExit:
            ESP_LOGI(TAG, "Exiting WiFi configuration mode");
            in_config_mode_ = false;
            // Attempt to reconnect after exiting config mode
            TryWifiConnect();
            break;

        default:
            ESP_LOGW(TAG, "Unknown network event received: %d", static_cast<int>(event));
            break;
    }
}

