void WifiBoard::StartWifiConfigMode()
{
    ESP_LOGI(TAG, "Starting WiFi configuration mode");

    // Set device state to configuring mode
    Application::GetInstance().SetDeviceState(kDeviceStateConfiguring);

    // Show notification to user
    GetDisplay()->ShowNotification(Lang::Strings::WIFI_CONFIG_MODE_STARTED);

    auto& wifi_manager = WifiManager::GetInstance();

    // Stop any ongoing station connection
    wifi_manager.StopStation();

    // Select and start appropriate provisioning method based on compile-time flags
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Bluetooth Low Energy provisioning via Blufi
    ESP_LOGI(TAG, "Starting Blufi provisioning");
    GetDisplay()->ShowNotification(Lang::Strings::BLUFI_PROVISIONING_STARTED);
    Blufi::GetInstance().init();
    wifi_manager.StartConfigMode(WifiConfigMode::BLE);

#elif defined(CONFIG_USE_ACOUSTIC_PROVISIONING)
    // Acoustic provisioning through audio input
    ESP_LOGI(TAG, "Starting acoustic provisioning");
    GetDisplay()->ShowNotification(Lang::Strings::ACOUSTIC_PROVISIONING_STARTED);
    // Initialize AFSK demodulator for acoustic provisioning
    afsk_demod_init();
    wifi_manager.StartConfigMode(WifiConfigMode::ACOUSTIC);

#else
    // Default to hotspot-based configuration with user prompts
    ESP_LOGI(TAG, "Starting hotspot provisioning");
    GetDisplay()->ShowNotification(Lang::Strings::HOTSPOT_PROVISIONING_STARTED);
    wifi_manager.StartConfigMode(WifiConfigMode::HOTSPOT);
#endif

    // Ensure the WiFi manager is in config mode
    in_config_mode_ = true;
}

