std::string WifiBoard::GetBoardJson()
{
    auto root = cJSON_CreateObject();

    // Add board type
    cJSON_AddStringToObject(root, "type", GetBoardType().c_str());

    // Add board name (using the class name or a descriptive name)
    cJSON_AddStringToObject(root, "name", "WiFi Board");

    // Add MAC address
    std::string mac_address = SystemInfo::GetMacAddress();
    cJSON_AddStringToObject(root, "mac_address", mac_address.c_str());

    // Add Wi-Fi details only when not in configuration mode
    if (!IsInWifiConfigMode()) {
        auto &wifi_manager = WifiManager::GetInstance();

        // Add SSID
        std::string ssid = wifi_manager.GetSsid();
        if (!ssid.empty()) {
            cJSON_AddStringToObject(root, "ssid", ssid.c_str());
        }

        // Add RSSI
        int rssi = wifi_manager.GetRssi();
        if (rssi != 0) { // 0 typically means not connected
            cJSON_AddNumberToObject(root, "rssi", rssi);
        }

        // Add channel
        int channel = wifi_manager.GetChannel();
        if (channel > 0) {
            cJSON_AddNumberToObject(root, "channel", channel);
        }

        // Add IP address
        std::string ip_address = wifi_manager.GetIpAddress();
        if (!ip_address.empty()) {
            cJSON_AddStringToObject(root, "ip_address", ip_address.c_str());
        }
    }

    // Serialize JSON to string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string ? json_string : "{}");

    // Clean up
    if (json_string) {
        cJSON_free(json_string);
    }
    cJSON_Delete(root);

    return result;
}

