void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level)
{
    auto& wifi_manager = WifiManager::GetInstance();

    // Map general power save levels to Wi-Fi specific values
    wifi_ps_type_t wifi_ps_level;
    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            wifi_ps_level = WIFI_PS_MAX_MODEM;
            break;
        case PowerSaveLevel::BALANCED:
            wifi_ps_level = WIFI_PS_MIN_MODEM;
            break;
        case PowerSaveLevel::PERFORMANCE:
            wifi_ps_level = WIFI_PS_NONE;
            break;
        default:
            ESP_LOGW(TAG, "Unknown power save level: %d, using balanced mode", static_cast<int>(level));
            wifi_ps_level = WIFI_PS_MIN_MODEM;
            break;
    }

    // Apply the Wi-Fi power save level through the Wi-Fi manager
    esp_err_t err = wifi_manager.SetPowerSaveMode(wifi_ps_level);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set Wi-Fi power save level: %s", esp_err_to_name(err));
    } else {
        ESP_LOGI(TAG, "Wi-Fi power save level set to %d", static_cast<int>(wifi_ps_level));
    }
}

