std::string WifiBoard::GetDeviceStatusJson()
{
    std::string json = "{";

    // Audio speaker volume
    auto codec = GetAudioCodec();
    if (codec) {
        json += "\"audio_volume\":" + std::to_string(codec->GetOutputVolume()) + ",";
    }

    // Display brightness and theme
    auto display = GetDisplay();
    if (display) {
        auto backlight = GetBacklight();
        if (backlight) {
            json += "\"screen_brightness\":" + std::to_string(backlight->GetBrightness()) + ",";
        }

        // Theme information if available
        #ifdef HAVE_LVGL
        auto theme = display->GetTheme();
        if (theme) {
            // Assuming we can determine light/dark theme somehow
            // For now, just indicate theme exists
            json += "\"screen_theme\":\"unknown\",";
        }
        #endif
    }

    // Battery level and charging state
    int battery_level = 0;
    bool charging = false;
    bool discharging = false;
    if (GetBatteryLevel(battery_level, charging, discharging)) {
        json += "\"battery_level\":" + std::to_string(battery_level) + ",";
        json += "\"battery_charging\":" + std::string(charging ? "true" : "false") + ",";
        json += "\"battery_discharging\":" + std::string(discharging ? "true" : "false") + ",";
    }

    // WiFi network details
    auto& wifi = WifiManager::GetInstance();
    if (!wifi.IsConfigMode() && wifi.IsConnected()) {
        json += "\"wifi_ssid\":\"" + wifi.GetSsid() + "\",";
        json += "\"wifi_rssi\":" + std::to_string(wifi.GetRssi()) + ",";
        json += "\"wifi_channel\":" + std::to_string(wifi.GetChannel()) + ",";
        json += "\"wifi_ip\":\"" + wifi.GetIpAddress() + "\",";
    }

    // Chip temperature
    float temperature = 0.0f;
    if (GetTemperature(temperature)) {
        json += "\"chip_temperature\":" + std::to_string(temperature);
    } else {
        // Remove trailing comma if present
        if (!json.empty() && json.back() == ',') {
            json.pop_back();
        }
    }

    json += "}";
    return json;
}

