        .name = "Blink Timer",
        .skip_unhandled_events = false,
    };
    ESP_ERROR_CHECK(esp_timer_create(&blink_timer_args, &blink_timer_));

    xTaskCreate(EventTask, "LedEvent", 2048, this, 
            tskIDLE_PRIORITY + 2, &event_task_handle_);

    ledc_initialized_ = true;
}

