bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (packet == nullptr || packet->payload.empty()) {
        ESP_LOGE(TAG, "Invalid audio packet");
        return false;
    }

    if (udp_ == nullptr) {
        ESP_LOGE(TAG, "UDP channel not available");
        return false;
    }

    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Update sequence number
    local_sequence_++;

    // Create dynamic nonce incorporating packet size, timestamp, and sequence number
    std::vector<uint8_t> dynamic_nonce(aes_nonce_.size());
    if (dynamic_nonce.size() >= 16) {
        // Copy base nonce
        std::copy(aes_nonce_.begin(), aes_nonce_.end(), dynamic_nonce.begin());

        // Incorporate packet size (2 bytes)
        uint16_t payload_size = htons(packet->payload.size());
        memcpy(dynamic_nonce.data(), &payload_size, std::min(sizeof(payload_size), static_cast<size_t>(2)));

        // Incorporate timestamp (4 bytes)
        uint32_t timestamp = htonl(packet->timestamp);
        memcpy(dynamic_nonce.data() + 4, &timestamp, std::min(sizeof(timestamp), static_cast<size_t>(4)));

        // Incorporate sequence number (4 bytes)
        uint32_t sequence = htonl(local_sequence_);
        memcpy(dynamic_nonce.data() + 8, &sequence, std::min(sizeof(sequence), static_cast<size_t>(4)));
    } else {
        // Fallback to base nonce if insufficient size
        dynamic_nonce = aes_nonce_;
    }

    // Encrypt the payload
    std::vector<uint8_t> encrypted_payload(packet->payload.size());
    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};

    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, packet->payload.size(), &nc_off, 
                                   dynamic_nonce.data(), stream_block,
                                   packet->payload.data(), encrypted_payload.data());

    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        return false;
    }

    // Construct UDP packet with headers
    /*
     * UDP Encrypted OPUS Packet Format:
     * |type 1u|flags 1u|payload_len 2u|ssrc 4u|timestamp 4u|sequence 4u|
     * |payload payload_len|
     */
    uint8_t type = 0x01;  // Audio packet type
    uint8_t flags = 0x00; // No flags
    uint16_t payload_len = htons(encrypted_payload.size());
    uint32_t ssrc = htonl(0x12345678); // Static SSRC or could be session-based
    uint32_t timestamp = htonl(packet->timestamp);
    uint32_t sequence = htonl(local_sequence_);

    // Calculate total packet size
    size_t header_size = sizeof(type) + sizeof(flags) + sizeof(payload_len) + 
                        sizeof(ssrc) + sizeof(timestamp) + sizeof(sequence);
    std::vector<uint8_t> udp_packet(header_size + encrypted_payload.size());

    // Fill packet headers
    size_t offset = 0;
    memcpy(udp_packet.data() + offset, &type, sizeof(type));
    offset += sizeof(type);
    memcpy(udp_packet.data() + offset, &flags, sizeof(flags));
    offset += sizeof(flags);
    memcpy(udp_packet.data() + offset, &payload_len, sizeof(payload_len));
    offset += sizeof(payload_len);
    memcpy(udp_packet.data() + offset, &ssrc, sizeof(ssrc));
    offset += sizeof(ssrc);
    memcpy(udp_packet.data() + offset, &timestamp, sizeof(timestamp));
    offset += sizeof(timestamp);
    memcpy(udp_packet.data() + offset, &sequence, sizeof(sequence));
    offset += sizeof(sequence);

    // Copy encrypted payload
    memcpy(udp_packet.data() + offset, encrypted_payload.data(), encrypted_payload.size());

    // Transmit the packet
    bool success = udp_->Send(std::string(reinterpret_cast<char*>(udp_packet.data()), udp_packet.size()));

    if (!success) {
        ESP_LOGE(TAG, "Failed to send audio packet over UDP");
        return false;
    }

    return true;
}

