void MqttProtocol::CloseAudioChannel()
{
    ESP_LOGI(TAG, "Closing audio channel, session_id: %s", session_id_.c_str());

    // Send goodbye message to server before closing UDP
    cJSON *root = cJSON_CreateObject();
    cJSON_AddStringToObject(root, "type", "goodbye");
    cJSON_AddStringToObject(root, "session_id", session_id_.c_str());

    char *json_string = cJSON_PrintUnformatted(root);
    if (json_string != nullptr) {
        std::string message(json_string);
        cJSON_free(json_string);

        // Send the goodbye message via MQTT
        SendText(message);
    }
    cJSON_Delete(root);

    // Reset the UDP connection
    std::lock_guard<std::mutex> lock(channel_mutex_);
    if (udp_ != nullptr) {
        udp_.reset();
    }

    // Clear session ID to indicate channel is closed
    session_id_.clear();

    // Trigger callback notification to inform application
    if (on_audio_channel_closed_ != nullptr) {
        on_audio_channel_closed_();
    }
}

