bool MqttProtocol::OpenAudioChannel()
{
    // Clear any previous error state
    error_occurred_ = false;

    // Ensure MQTT client is connected
    if (mqtt_ == nullptr || !mqtt_->IsConnected()) {
        ESP_LOGE(TAG, "MQTT client not connected");
        SetError(Lang::Strings::SERVER_NOT_CONNECTED);
        return false;
    }

    // Clear event bits before starting
    xEventGroupClearBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);

    // Send hello message to request UDP channel
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    ESP_LOGI(TAG, "Hello message sent, waiting for server response");

    // Wait for server hello response with timeout
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,  // Clear bits on exit
        pdFALSE, // Wait for any bit
        pdMS_TO_TICKS(10000) // 10 second timeout
    );

    if ((bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT) == 0) {
        ESP_LOGE(TAG, "Timeout waiting for server hello response");
        SetError(Lang::Strings::SERVER_TIMEOUT);
        return false;
    }

    ESP_LOGI(TAG, "Server hello received, setting up UDP connection");

    // Create UDP connection with server-provided address and port
    auto network = Board::GetInstance().GetNetwork();
    udp_ = network->CreateUdp();

    if (udp_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create UDP socket");
        SetError(Lang::Strings::NETWORK_ERROR);
        return false;
    }

    // Connect to UDP server
    if (!udp_->Connect(udp_server_, udp_port_)) {
        ESP_LOGE(TAG, "Failed to connect to UDP server %s:%d", udp_server_.c_str(), udp_port_);
        SetError(Lang::Strings::NETWORK_ERROR);
        udp_.reset();
        return false;
    }

    // Set up UDP receive callback for audio packets
    udp_->OnDataReceived([this](const uint8_t* data, size_t len) {
        if (len < aes_nonce_.size()) {
            ESP_LOGW(TAG, "Received UDP packet too short: %d bytes", len);
            return;
        }

        // Extract nonce from packet header
        std::string nonce((const char*)data, aes_nonce_.size());
        uint32_t packet_sequence = ntohl(*(uint32_t*)&nonce[12]);

        // Check packet sequence to ensure proper ordering
        if (packet_sequence <= remote_sequence_) {
            ESP_LOGW(TAG, "Duplicate or out-of-order packet: expected >%u, got %u", 
                     remote_sequence_, packet_sequence);
            return;
        }
        remote_sequence_ = packet_sequence;

        // Decrypt audio data using AES-CTR
        std::vector<uint8_t> decrypted(len - aes_nonce_.size());
        size_t nc_off = 0;
        uint8_t stream_block[16] = {0};

        int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, 
                                       len - aes_nonce_.size(),
                                       &nc_off,
                                       (uint8_t*)nonce.c_str(),
                                       stream_block,
                                       data + aes_nonce_.size(),
                                       decrypted.data());

        if (ret != 0) {
            ESP_LOGE(TAG, "Failed to decrypt audio packet: %d", ret);
            return;
        }

        // Create audio packet and pass to callback
        auto packet = std::make_unique<AudioStreamPacket>();
        packet->sample_rate = server_sample_rate_;
        packet->frame_duration = server_frame_duration_;
        packet->timestamp = ntohl(*(uint32_t*)&nonce[8]);
        packet->payload.assign(decrypted.begin(), decrypted.end());

        if (on_incoming_audio_) {
            on_incoming_audio_(std::move(packet));
        }
    });

    ESP_LOGI(TAG, "Audio channel opened successfully");

    // Notify that audio channel is opened
    if (on_audio_channel_opened_) {
        on_audio_channel_opened_();
    }

    return true;
}

