{
    std::string result;

    // Handle empty string case
    if (hex_string.empty()) {
        return result;
    }

    // Check if length is even - each byte should be represented by 2 hex characters
    if (hex_string.length() % 2 != 0) {
        // For odd length, we could either return empty or process as best we can
        // Following common practice, we'll process pairs and ignore the last character if odd
        // But better approach is to validate and return empty for invalid input
        return result;
    }

    // Process the hex string in pairs
    for (size_t i = 0; i < hex_string.length(); i += 2) {
        // Convert each character to its hex value
        uint8_t high_nibble = CharToHex(hex_string[i]);
        uint8_t low_nibble = CharToHex(hex_string[i + 1]);

        // Combine the two nibbles into a single byte
        uint8_t byte_value = (high_nibble << 4) | low_nibble;

        // Append the byte to result
        result.push_back(static_cast<char>(byte_value));
    }

    return result;
}

