bool Protocol::IsTimeout() const {
    // Get current time in microseconds
    int64_t current_time = esp_timer_get_time();

    // Calculate elapsed time since last message
    int64_t elapsed_time_us = current_time - last_message_time_;

    // Convert 120 seconds to microseconds
    const int64_t timeout_threshold_us = 120 * 1000 * 1000;

    // Check if elapsed time exceeds the threshold
    if (elapsed_time_us > timeout_threshold_us) {
        ESP_LOGE(TAG, "Channel timeout: No message received for %lld seconds", 
                 elapsed_time_us / 1000000);
        return true;
    }

    return false;
}

