std::string WebsocketProtocol::GetHelloMessage() {
    cJSON* root = cJSON_CreateObject();

    // Set message type
    cJSON_AddStringToObject(root, "type", "hello");

    // Set protocol version
    cJSON_AddNumberToObject(root, "version", version_);

    // Set supported features
    cJSON* features = cJSON_CreateObject();
    cJSON_AddBoolToObject(features, "aec", true);   // Acoustic Echo Cancellation supported
    cJSON_AddBoolToObject(features, "mcp", true);   // Multi-Channel Processing supported
    cJSON_AddItemToObject(root, "features", features);

    // Set transport method
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Set audio parameters
    cJSON* audio_params = cJSON_CreateObject();
    cJSON_AddStringToObject(audio_params, "format", "pcm");           // Audio format
    cJSON_AddNumberToObject(audio_params, "sample_rate", 16000);      // Sample rate in Hz
    cJSON_AddNumberToObject(audio_params, "channels", 1);             // Number of channels
    cJSON_AddNumberToObject(audio_params, "frame_duration", 20);      // Frame duration in ms
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Convert to string
    char* json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string);
    cJSON_free(json_string);
    cJSON_Delete(root);

    return result;
}

